#include <stdio.h>
#include <stdlib.h>

int cmp(const void *a, const void *b) {
    int x = *(const int *)a;
    int y = *(const int *)b;
    return x - y;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; long long H; scanf("%d %lld", &N, &H);
        int *a = (int *)malloc(N * sizeof(int));
        long long total = 0;
        for (int i = 0; i < N; ++i) {
            scanf("%d", &a[i]);
            total += a[i];
        }
        long long need = total - (H - 1);
        if (need <= 0) {
            printf("0\n");
            free(a);
            continue;
        }
        qsort(a, N, sizeof(int), cmp);
        long long pref = 0;
        int ans = 0;
        for (int i = 0; i < N; ++i) {
            pref += a[i];
            if (pref >= need) { ans = a[i]; break; }
        }
        printf("%d\n", ans);
        free(a);
    }
    return 0;
}

